import csv
import json
import sys
from pathlib import Path

def main():
    if len(sys.argv) < 3:
        print(f"Usage: {sys.argv[0]} <input_path> <output_path>", file=sys.stderr)
        sys.exit(1)

    input_path = Path(sys.argv[1])
    output_path = Path(sys.argv[2])

    if input_path.suffix not in ('.csv', '.jsonl'):
        print(f"Error: Unsupported input extension '{input_path.suffix}'. Must be .csv or .jsonl", file=sys.stderr)
        sys.exit(1)
    if output_path.suffix not in ('.csv', '.jsonl'):
        print(f"Error: Unsupported output extension '{output_path.suffix}'. Must be .csv or .jsonl", file=sys.stderr)
        sys.exit(1)

    rows = []
    if input_path.suffix == '.csv':
        with open(input_path, mode='r', encoding='utf-8-sig', newline='') as f:
            reader = csv.DictReader(f, skipinitialspace=True)
            raw_headers = reader.fieldnames if reader.fieldnames else []
            headers = [h.strip() for h in raw_headers]
            for row in reader:
                stripped_row = {}
                for raw_h, h in zip(raw_headers, headers):
                    val = row.get(raw_h)
                    stripped_row[h] = val.strip() if val is not None else ""
                rows.append(stripped_row)
    elif input_path.suffix == '.jsonl':
        with open(input_path, mode='r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if line:
                    rows.append(json.loads(line))

    # No transformations to apply

    if rows:
        fieldnames = list(rows[0].keys())
    else:
        fieldnames = ["ID", "FirstName", "LastName", "DOB", "Country", "Phone"]

    if output_path.suffix == '.csv':
        with open(output_path, mode='w', encoding='utf-8', newline='') as f:
            writer = csv.DictWriter(f, fieldnames=fieldnames)
            writer.writeheader()
            for row in rows:
                writer.writerow(row)
    elif output_path.suffix == '.jsonl':
        with open(output_path, mode='w', encoding='utf-8') as f:
            for row in rows:
                f.write(json.dumps(row) + '\n')

if __name__ == '__main__':
